function EmailReplierWidget() {
  const [tone, setTone] = React.useState('professional');
  const [subject, setSubject] = React.useState('');
  const [body, setBody] = React.useState('');

  const templates = {
    professional: 'Dear Team,\n\nThank you for reaching out.\n\nBest regards,',
    friendly: 'Hey there!\n\nThanks for your message—happy to help.',
    formal: 'To Whom It May Concern,\n\nPlease find the requested information below.',
    concise: 'Acknowledged. Here is the response:'
  };

  function applyTone() {
    setBody(templates[tone]);
  }

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#0f172a', color: '#e2e8f0', borderRadius: 12, height: '100%', display: 'flex', flexDirection: 'column' }}>
      <h3 style={{ margin: 0, marginBottom: 10 }}>Email Replier</h3>
      <div style={{ display: 'flex', gap: 8, marginBottom: 10, alignItems: 'center' }}>
        <select
          value={tone}
          onChange={(e) => setTone(e.target.value)}
          style={{ padding: 8, borderRadius: 6, border: '1px solid #334155', background: '#1e293b', color: '#e2e8f0', fontFamily: 'system-ui, sans-serif' }}
        >
          <option value="professional">Professional</option>
          <option value="friendly">Friendly</option>
          <option value="formal">Formal</option>
          <option value="concise">Concise</option>
        </select>
        <button onClick={applyTone} style={{ padding: '8px 14px', borderRadius: 6, border: 'none', background: '#3b82f6', color: '#fff', fontWeight: 600, cursor: 'pointer', fontFamily: 'system-ui, sans-serif' }}>Apply Tone</button>
      </div>
      <input
        value={subject}
        onChange={(e) => setSubject(e.target.value)}
        placeholder="Subject"
        style={{ padding: 8, borderRadius: 6, border: '1px solid #334155', background: '#1e293b', color: '#e2e8f0', fontFamily: 'system-ui, sans-serif', marginBottom: 8 }}
      />
      <textarea
        value={body}
        onChange={(e) => setBody(e.target.value)}
        placeholder="Compose your reply..."
        style={{ flex: 1, padding: 10, borderRadius: 8, border: '1px solid #334155', background: '#1e293b', color: '#e2e8f0', fontFamily: 'system-ui, sans-serif', fontSize: 13, resize: 'none', minHeight: 0 }}
      />
    </div>
  );
}
render(<EmailReplierWidget/>);
